    id: "cs_interfaces_5",
    topicId: "cs_interfaces",
    question: "Demonstrate explicit interface implementation to resolve naming conflicts.",
    mathSolution: "Explicit implementation for methods with same name across interfaces.",
    codeSolution: "using System;\n\ninterface IPrintable\n{\n    void Print();\n}\n\ninterface IScannable\n{\n    void Print();\n}\n\nclass MultiFunctionPrinter : IPrintable, IScannable\n{\n    void IPrintable.Print()\n    {\n        Console.WriteLine(\"Printing document\");\n    }\n    \n    void IScannable.Print()\n    {\n        Console.WriteLine(\"Scanning document\");\n    }\n    \n    public void PrintBoth()\n    {\n        ((IPrintable)this).Print();\n        ((IScannable)this).Print();\n    }\n}\n\nclass Program\n{\n    static void Main()\n    {\n        MultiFunctionPrinter mfp = new MultiFunctionPrinter();\n        mfp.PrintBoth();\n        \n        IPrintable printable = mfp;\n        printable.Print(); // Prints\n        \n        IScannable scannable = mfp;\n        scannable.Print(); // Scans\n    }\n}",
    hint: "Explicit implementation uses InterfaceName.MethodName syntax.",
